import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../../types';

export type ScalaProfilerProps = IconProps;

const ScalaProfilerLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      d="m15.5 9.5-5 .5m5 2.25-5 .5m5 2.25-5 .5"
      stroke="#6C707E"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
    <path
      d="M1.5 10a6.5 6.5 0 0 1 12.724-1.88l1.012-.1A7.5 7.5 0 0 0 .5 10c0 1.16.377 2.68.866 3.73.079.168.25.27.435.27h7.207v-1H2.139c-.37-.913-.639-2.11-.639-3"
      fill="#6C707E"
    />
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="m10.558 8.487-.207.02a1.5 1.5 0 0 0-1.343 1.642v1.143a1.8 1.8 0 1 1-.08-3.035l2.477-1.99a.6.6 0 1 1 .752.935zM8 10.6A.8.8 0 1 0 8 9a.8.8 0 0 0 0 1.6"
      fill="#6C707E"
    />
  </svg>
);

const ScalaProfilerDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <g clipPath="url(#a)">
      <path
        d="m15.5 9.5-5 .5m5 2.25-5 .5m5 2.25-5 .5"
        stroke="#CED0D6"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M1.5 10a6.5 6.5 0 0 1 12.724-1.88l1.012-.1A7.5 7.5 0 0 0 .5 10c0 1.16.377 2.68.866 3.73.079.168.25.27.435.27h7.207v-1H2.139c-.37-.913-.639-2.11-.639-3"
        fill="#CED0D6"
      />
      <path
        fillRule="evenodd"
        clipRule="evenodd"
        d="m10.558 8.487-.207.02a1.5 1.5 0 0 0-1.343 1.642v1.143a1.8 1.8 0 1 1-.08-3.035l2.477-1.99a.6.6 0 1 1 .752.935zM8 10.6A.8.8 0 1 0 8 9a.8.8 0 0 0 0 1.6"
        fill="#CED0D6"
      />
    </g>
    <defs>
      <clipPath id="a">
        <path fill="#fff" d="M0 0H16V16H0z" />
      </clipPath>
    </defs>
  </svg>
);

export const ScalaProfiler: FC<ScalaProfilerProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light' ? ScalaProfilerLight : ScalaProfilerDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
